private static boolean isJSIdentifierStart(char c) {
    return Character.isLetter(c) || c == '$' || c == '_' || Character.getType(c) == Character.LETTER_NUMBER;
}

private static boolean isJSIdentifierPart(char c) {
    return Character.isLetterOrDigit(c) || c == '$' || c == '_' || Character.getType(c) == Character.LETTER_NUMBER;
}

private static boolean isReservedKeyword(String s) {
    String[] keywords = {
        "break", "case", "catch", "class", "const", "continue", "debugger", "default", "delete", "do",
        "else", "export", "extends", "finally", "for", "function", "if", "import", "in", "instanceof",
        "new", "return", "super", "switch", "this", "throw", "try", "typeof", "var", "void", "while",
        "with", "yield", "enum", "await", "implements", "package", "protected", "interface", "private",
        "public"
    };
    for (String keyword : keywords) {
        if (s.equals(keyword)) {
            return true;
        }
    }
    return false;
}

public static boolean isJSIdentifier(String s) {
  if (s.isEmpty()) {
    return false;
  }

  char firstChar = s.charAt(0);
  if (!Character.isLetter(firstChar) && firstChar != '$' && firstChar != '_') {
    return false;
  }

  for (int i = 1; i < s.length(); i++) {
    char c = s.charAt(i);
    if (!Character.isLetterOrDigit(c) && c != '$' && c != '_') {
      return false;
    }
  }

  return true;
}

